"use client";

import { useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import { useMemo, useState } from "react";

import { AIConversation, AIMessage, AIPromptInput, AIStatus } from "@/components/ai-elements";

export function ChatbotShell() {
  const [input, setInput] = useState("");
  const transport = useMemo(() => new DefaultChatTransport({ api: "/api/ai/chat" }), []);
  const { messages, sendMessage, status } = useChat({ transport });
  const disabled = status === "submitted" || status === "streaming";

  function submit() {
    const text = input.trim();
    if (!text || disabled) return;
    sendMessage({ text });
    setInput("");
  }

  return (
    <AIConversation>
      {messages.map((message) => (
        <AIMessage key={message.id} message={message} />
      ))}
      <AIStatus status={status} />
      <AIPromptInput disabled={disabled} value={input} onSubmit={submit} onValueChange={setInput} />
    </AIConversation>
  );
}

import { ChatbotShell } from "@/components/ai/chatbot-shell";

export default function AIChatbotPage() {
  return (
    <main className="mx-auto flex max-w-3xl flex-col gap-6 p-6">
      <div>
        <p className="text-sm font-medium text-muted-foreground">AI</p>
        <h1 className="text-3xl font-semibold tracking-tight">Chatbot</h1>
        <p className="mt-2 text-muted-foreground">
          A Vercel AI SDK chat surface built from source-owned AI Elements primitives.
        </p>
      </div>
      <ChatbotShell />
    </main>
  );
}
